<script lang="ts">
	import { page } from "$app/state";
	import Icon from "$lib/components/Icon.svelte";
	import IconButton from "$lib/components/IconButton.svelte";
	import LibraryItemCard from "$lib/components/LibraryItemCard.svelte";
	import LibraryManagerSession, { type LibraryChatMessage } from "$lib/components/LibraryManagerSession.svelte";
	import ModalSurface from "$lib/components/ModalSurface.svelte";
	import { libraryLinks, libraryProvenance, type LibraryItemView, type LibraryKind } from "$lib/data/library";
	import { searchLibrary, sendLibraryManagerMessage, type LibraryManagerAction } from "./library-manager.remote";
	let { data } = $props();
	const lib = $derived(data.library);
	let view = $state<"desk"|"graph"|"kanban"|"table">("desk");
	let query = $state("");
	let kind = $state<LibraryKind|null>(null);
	let project = $state<string|null>(null); let scope = $state<string|null>(null); let creator = $state<string|null>(null); let status = $state<string|null>(null);
	let messages = $state<LibraryChatMessage[]>([]);
	let managerBusy = $state(false);
	let managerSessionId = $state<string|null>(null);
	let selected = $state<LibraryItemView|null>(null);
	let drawer = $state<HTMLDialogElement|null>(null);
	let search = $state<HTMLInputElement|null>(null);
	let searchResults=$state<LibraryItemView[]|null>(null);
	let searchState=$state<"idle"|"searching"|"failed">("idle");
	let handledItem=$state<string|null>(null);
	const results = $derived((searchResults??lib.items).filter((item) => (!kind || item.kind === kind) && (!project || item.project === project) && (!scope || item.scope === scope) && (!creator || item.creator === creator) && (!status || item.status === status) && (searchResults!==null || `${item.title} ${item.project} ${item.kind} ${item.creator}`.toLowerCase().includes(query.toLowerCase()))));
	const links=$derived(lib.links ?? libraryLinks);
	const provenance=$derived(lib.provenance ?? libraryProvenance);
	const graphHeight=$derived(Math.max(480, Math.ceil(lib.items.length/4)*112));
	const graphPositions=$derived.by(()=>Object.fromEntries(lib.items.map((item,index)=>[item.id,[14+(index%4)*24,64+Math.floor(index/4)*112] as [number,number]])) as Record<string,[number,number]>);
	const graphEdges=$derived(Object.entries(links).flatMap(([from,itemLinks])=>itemLinks.filter(link=>graphPositions[from]&&graphPositions[link.targetId]).map(link=>({from,to:link.targetId,rel:link.rel}))));
	function open(item: LibraryItemView){ selected=item; }
	async function runSearch(nextQuery:string){query=nextQuery;view="table";if(lib.isMock||!nextQuery.trim()){searchResults=null;searchState="idle";return;}searchState="searching";try{searchResults=await searchLibrary({query:nextQuery});searchState="idle";}catch{searchResults=[];searchState="failed";}}
	async function submit(e:SubmitEvent){e.preventDefault();await runSearch(query);}
	function applyManagerAction(action:LibraryManagerAction){const {intent}=action;if(intent.view&&["desk","graph","kanban","table"].includes(intent.view))view=intent.view;if(typeof intent.query==="string"){query=intent.query;searchResults=action.items;searchState="idle";view="table";}if(typeof intent.item_id==="string")selected=action.item??(searchResults??lib.items).find(item=>item.id===intent.item_id)??null;if(intent.focus==="curation")queueMicrotask(()=>document.querySelector<HTMLElement>(".curation")?.scrollIntoView({behavior:"smooth",block:"center"}));}
	async function ask(message:string){const userMessage:LibraryChatMessage={id:crypto.randomUUID(),role:"user",content:message};messages=[...messages,userMessage];managerBusy=true;try{const response=await sendLibraryManagerMessage({message,view,query,selected_item_id:selected?.id??null});managerSessionId=response.session_id;messages=[...messages,{id:response.message_id,role:"assistant",content:response.content}];if(response.library_action)applyManagerAction(response.library_action);}catch(error){messages=[...messages,{id:crypto.randomUUID(),role:"error",content:`The manager session could not continue. ${(error as Error).message}`}];}finally{managerBusy=false;}}
	function keys(e:KeyboardEvent){ if(e.key==="f" && !(e.target instanceof HTMLInputElement)){e.preventDefault();search?.focus();} if(["1","2","3","4"].includes(e.key)&&!(e.target instanceof HTMLInputElement)) view=(["desk","graph","kanban","table"] as const)[Number(e.key)-1]; }
	function graphKey(e:KeyboardEvent){if(!e.key.startsWith("Arrow"))return;const nodes=[...document.querySelectorAll<HTMLButtonElement>(".graph button")];const i=nodes.indexOf(e.currentTarget as HTMLButtonElement);if(i>=0){e.preventDefault();nodes[(i+(e.key==="ArrowLeft"||e.key==="ArrowUp"?-1:1)+nodes.length)%nodes.length]?.focus();}}
	$effect(()=>{const id=page.url.searchParams.get("item");if(!id||id===handledItem)return;handledItem=id;selected=lib.items.find((item)=>item.id===id)??null;});
	$effect(()=>{if(page.url.searchParams.get("focus")!=="search")return;queueMicrotask(()=>search?.focus());});
</script>
<svelte:window onkeydown={keys}/>
<div class="sign"><h1>The Library</h1><span>Everything anyone here has ever learned. Ask.</span><form onsubmit={submit} title={lib.connected?"Search the stacks":"Store unreachable"}><Icon name="search" size={14}/><input bind:this={search} bind:value={query} placeholder="Search the stacks" aria-label="Search the stacks" disabled={!lib.connected}/></form><div class="seg">{#each ["desk","graph","kanban","table"] as tab}<button class:on={view===tab} onclick={() => view=tab as typeof view} disabled={!lib.connected}>{tab[0].toUpperCase()+tab.slice(1)}</button>{/each}</div><button class="bud" title="Budhole" aria-label="Budhole" disabled={!lib.connected}><Icon name="library" size={16}/></button></div>
<div class="ask">
	<LibraryManagerSession {messages} busy={managerBusy} connected={data.managerConnected} isMock={lib.isMock} sessionId={managerSessionId} onask={ask}/>
</div>
{#if !lib.connected}<div class="unavailable"><Icon name="circle-help" size={18}/><div><b>The stacks are unreachable.</b><p>No current Library items are rendered. The manager remains available if its runtime is healthy.</p></div></div>{/if}
{#if lib.connected}
{#if view==="desk"}
	<div class="desk"><main><section class="panel"><header><h2>Held for you</h2><span>the librarian set these aside</span></header><div class="two">{#each lib.items.filter(i=>i.hold?.startsWith("Held")).slice(0,2) as item}<LibraryItemCard {item} onopen={open}/>{:else}<p class="empty">Nothing held aside for you yet.</p>{/each}</div><footer><Icon name="scroll-text" size={12}/> {lib.isMock?"fixture receipt":"personal holds · 60s freshness"}</footer></section><section class="panel"><header><h2>Recommended for you</h2><span>your reading room, not a feed</span></header><div class="two">{#each lib.items.filter(i=>i.hold?.startsWith("Recommended")).slice(0,2) as item}<LibraryItemCard {item} onopen={open}/>{:else}<p class="empty">No recommendations have fresh evidence yet.</p>{/each}</div><footer><Icon name="scroll-text" size={12}/> librarian picks · reason recorded</footer></section><section class="panel"><header><h2>Readable stacks</h2><span>recent items in your scopes</span></header>{#each lib.items.slice(0,3) as item}<LibraryItemCard {item} compact onopen={open}/>{:else}<p class="empty">Your readable stacks are empty.</p>{/each}<footer><Icon name="scroll-text" size={12}/> scope-filtered by Library RLS</footer></section></main><aside><section class="panel"><header><h2>Recent arrivals</h2><span>your scopes</span></header>{#each lib.items.slice(0,3) as item}<LibraryItemCard {item} compact onopen={open}/>{/each}</section><section class="panel curation"><header><h2>Curation</h2><span>librarian · review queue</span></header><p>{lib.curation?.length??0} reviewable {lib.curation?.length===1?"proposal":"proposals"} in your scopes.</p><small>{lib.sources?.curation==="live"?"live Library curation queue":"curation source unavailable"}</small><button disabled title="Approval actions are not wired yet">Review {lib.curation?.length??0}</button></section><section class="panel"><header><h2>Tool registry</h2><span>{lib.sources?.capabilities==="live"?`${lib.capabilities?.filter(c=>c.fresh).length??0} fresh · ${lib.capabilities?.filter(c=>!c.fresh).length??0} stale`:"unavailable"}</span></header><div class="tool-inventory">{#each lib.capabilities??[] as capability}<p class="capability"><code>{capability.capability}</code><small>{capability.provider}{capability.transport?` · ${capability.transport}`:""}{capability.fresh?"":" · stale"}</small></p>{:else}<p class="caption">No visible capabilities have registry evidence.</p>{/each}</div></section><section class="panel"><header><h2>Check before web</h2></header>{#if lib.isMock}<div class="kpi">87%<small>stacks answered first</small></div><p class="caption">9 fixture web fallbacks this week.</p>{:else}<p class="caption">Hit-rate evidence is unavailable. Research egress remains disabled.</p>{/if}</section></aside></div>
{:else if view==="table"}
	<div class="facets"><span>{searchState==="searching"?"Searching the stacks…":searchState==="failed"?"Search failed · nothing pretended":`${results.length} results · ${lib.isMock?"hybrid-search fixture":searchResults!==null?"Library lexical search · dense unavailable":"local filter over scope-filtered Library items"}`}</span><button class:on={kind==="how-to"} onclick={()=>kind=kind==="how-to"?null:"how-to"}>kind: how-to</button><button class:on={project==="fleet"} onclick={()=>project=project==="fleet"?null:"fleet"}>project: fleet</button><button class:on={scope==="fleet-public"} onclick={()=>scope=scope==="fleet-public"?null:"fleet-public"}>scope: fleet-public</button><button class:on={creator==="carson-2"} onclick={()=>creator=creator==="carson-2"?null:"carson-2"}>created-by: carson-2</button><button class:on={status==="verified-shared"} onclick={()=>status=status==="verified-shared"?null:"verified-shared"}>status: verified</button></div><div class="table"><div class="head"><span>title</span><span>project</span><span>updated</span><span>conf</span></div>{#each results as item}<button class="row" onclick={()=>open(item)}><span><b>{item.title}</b><small>{item.kind} · {item.scope} · by {item.creator}</small><em>{lib.isMock?`hybrid match · dense ${item.confidence?.toFixed(2)||"—"}`:searchResults!==null?"Library lexical match · dense index unavailable":"local title and facet match · dense index unavailable"}</em></span><code>{item.project}</code><code>{item.updated}</code><code>{item.confidence?.toFixed(2)||"—"}</code></button>{:else}<div class="empty">Nothing in the stacks for that. Research is unavailable until sole egress is wired.</div>{/each}</div>
{:else if view==="kanban"}
	<div class="kanban-note">Status writes are disabled until <code>library.item.update</code> lands. Conflicts will float to the adjudication rail.</div><h2 class="lane-group">Work · task lifecycle</h2><div class="kanban">{#each ["todo","doing","review","done"] as lane}<section><h2>{lane}</h2>{#each lib.items.filter(i=>i.kind==="task"&&i.status===lane) as item}<LibraryItemCard {item} compact onopen={open}/>{:else}<p>All caught up.</p>{/each}</section>{/each}</div><h2 class="lane-group">Knowledge · promotion lifecycle</h2><div class="kanban knowledge">{#each ["draft","verified-shared","superseded","invalidated"] as lane}<section><h2>{lane}</h2>{#each lib.items.filter(i=>i.kind!=="task"&&i.status===lane) as item}<LibraryItemCard {item} compact onopen={open}/>{:else}<p>All caught up.</p>{/each}</section>{/each}</div>
{:else}
	<div class="graph-scroll"><div class="graph" style={`height:${graphHeight}px`} aria-label="Typed-link dependency graph"><svg viewBox={`0 0 100 ${graphHeight}`} preserveAspectRatio="none" role="img" aria-label="Library item links"><defs><marker id="arrow" markerWidth="3" markerHeight="3" refX="2" refY="1.5" orient="auto"><path d="M0 0L3 1.5L0 3z"/></marker></defs>{#each graphEdges as edge}<line x1={graphPositions[edge.from][0]} y1={graphPositions[edge.from][1]} x2={graphPositions[edge.to][0]} y2={graphPositions[edge.to][1]}><title>{edge.rel}</title></line>{/each}</svg>{#each lib.items as item}<button style={`--x:${graphPositions[item.id][0]}%;--y:${graphPositions[item.id][1]}px`} onclick={()=>open(item)} onkeydown={graphKey}><Icon name={item.kind==="decision"?"milestone":item.kind==="research"?"microscope":"file-text"} size={16}/><span>{item.title}</span></button>{/each}<small>{lib.items.length} scope-filtered items · {lib.isMock?"fixture typed links":"live typed links"} · arrows walk nodes</small></div></div>
{/if}
<ModalSurface bind:element={drawer} open={selected!==null} variant="drawer" labelledby="library-item-title" onclose={()=>selected=null}>{#if selected}<div class="library-drawer"><IconButton class="dialog-close" name="x" label="Close item" autofocus onclick={()=>drawer?.close()}/><header><Icon name="book-open" size={16}/><h2 id="library-item-title">{selected.title}</h2></header><div class="chips"><span>{selected.kind}</span><span>{selected.status}</span><span><Icon name="shield" size={11}/> {selected.protection??"unknown"}</span><span>{selected.scope}</span><span>conf {selected.confidence?.toFixed(2)||"—"}</span></div><article>{selected.body}</article><section><h3>Typed links</h3>{#each links[selected.id] ?? [] as link}<button class="link" onclick={()=>{const target=lib.items.find(i=>i.id===link.targetId);if(target)selected=target}}><Icon name={link.direction==="out"?"arrow-right":"arrow-left"} size={12}/><code>{link.rel}</code><span>{lib.items.find(i=>i.id===link.targetId)?.title??"target not visible"}</span>{#if link.reason}<small>{link.reason}</small>{/if}</button>{:else}<p>No typed links filed.</p>{/each}</section><section><h3>Provenance</h3><p>created-by-agent:{selected.creator} · responsible-human:{provenance[selected.id]?.responsibleHuman??"unassigned"} · handed-off-to-agent:{selected.handedOffTo??"none"} · v{selected.version}</p></section><footer>v{selected.version} · tx_from {provenance[selected.id]?.txFrom??"unavailable"} · what did we believe when</footer></div>{/if}</ModalSurface>
{/if}
<style>
	.sign{display:flex;align-items:center;gap:var(--s-3);min-height:40px}.sign h1{font:400 1.0625rem var(--sign)}.sign>span{font:400 .875rem var(--sign);color:var(--jade-text)}.sign form{margin-inline-start:auto;width:320px;min-height:32px;display:flex;align-items:center;gap:var(--s-2);padding:0 var(--s-2);background:var(--s2);border-radius:var(--r-sm)}input{border:0;outline:0;background:none;color:var(--text);width:100%;font-size:.75rem}.sign form:focus-within{box-shadow:0 0 0 2px var(--petal)}.seg{display:flex;background:var(--s2);border-radius:var(--r-sm);padding:var(--s-1)}.seg button,.bud{border:0;background:none;color:var(--text-2);min-height:32px;padding:0 var(--s-2);border-radius:var(--r-sm);text-transform:capitalize}.seg button.on{background:var(--petal-soft);color:var(--petal-text)}.bud{width:32px;padding:0}.unavailable{display:flex;gap:var(--s-2);background:var(--warn-soft);color:var(--warn-text);padding:var(--s-3);margin-top:var(--s-3);border-radius:var(--r-xs)}.unavailable p{font-size:.75rem;color:var(--text-2)}.ask{margin:var(--s-4) 0}.desk{display:grid;grid-template-columns:minmax(0,1fr) 344px;gap:var(--s-3);padding-bottom:var(--s-4)}.desk main,.desk aside{display:flex;flex-direction:column;gap:var(--s-3)}.panel{background:var(--s1);border-radius:var(--r-xs);padding:var(--s-3)}.panel header{display:flex;align-items:baseline;gap:var(--s-2);margin-bottom:var(--s-2)}.panel h2{font-size:.84375rem}.panel header span{font-size:.6875rem;color:var(--text-3)}.panel footer{display:flex;align-items:center;gap:var(--s-2);border-top:1px solid var(--rule);padding-top:var(--s-2);margin-top:var(--s-2);font:400 .6875rem var(--mono);color:var(--text-3)}.two{display:grid;grid-template-columns:1fr 1fr;gap:var(--s-2)}.empty{padding:var(--s-3);font-size:.8125rem;color:var(--text-3)}.curation p{font-size:.8125rem;color:var(--text-2)}.curation small{display:block;color:var(--text-3);margin:var(--s-2) 0}.curation button{border:0;background:var(--s2);border-radius:var(--r-sm);min-height:32px;padding:0 var(--s-3)}.tool-inventory{max-height:240px;overflow:auto}.kpi{font:500 1.75rem var(--mono)}.kpi small{display:block;font:400 .75rem var(--sans);color:var(--text-3)}.caption{font-size:.75rem;color:var(--text-3)}.facets{display:flex;align-items:center;gap:var(--s-2);margin:var(--s-3) 0}.facets>span{margin-inline-end:auto;font:400 .6875rem var(--mono);color:var(--text-3)}.facets button{border:0;background:var(--s2);border-radius:var(--r-pill);min-height:24px;color:var(--text-2)}.facets button.on{background:var(--petal-soft);color:var(--petal-text)}.table{background:var(--s1);border-radius:var(--r-xs)}.head,.row{display:grid;grid-template-columns:1fr 120px 80px 64px;gap:var(--s-2);align-items:center}.head{min-height:32px;padding:0 var(--s-3);font:500 .6875rem var(--mono);color:var(--text-3)}.row{width:100%;border:0;border-top:1px solid var(--rule);background:none;color:var(--text);text-align:left;min-height:64px;padding:var(--s-1) var(--s-3)}.row:hover{background:var(--s2)}.row b,.row small,.row em{display:block}.row b{font-size:.8125rem}.row small,.row em{font:400 .6875rem var(--mono);color:var(--text-3)}.row em{color:var(--jade-text);margin-top:var(--s-1)}.row code{text-align:right}.kanban{display:grid;grid-template-columns:repeat(4,1fr);gap:var(--s-3);margin-top:var(--s-3)}.kanban section{background:var(--s2);padding:var(--s-2);border-radius:var(--r-xs)}.kanban h2{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3)}.kanban p{font-size:.75rem;color:var(--text-3);padding:var(--s-2)}.graph-scroll{max-height:640px;overflow:auto;margin-top:var(--s-3);border-radius:var(--r-xs)}.graph{min-height:480px;background:var(--s1);position:relative}.graph svg{position:absolute;inset:0;width:100%;height:100%}.graph path{fill:none;stroke:var(--text-3);stroke-width:1;marker-end:url(#arrow)}.graph button{position:absolute;left:var(--x);top:var(--y);width:140px;border:0;background:var(--s2);color:var(--text);border-radius:var(--r-xs);padding:var(--s-2)}.graph button span{display:block;font:400 .6875rem var(--mono);margin-top:var(--s-1)}.chips{display:flex;gap:var(--s-1);flex-wrap:wrap;margin:var(--s-3) 0}.chips span{display:flex;align-items:center;gap:var(--s-1);background:var(--s2);border-radius:var(--r-pill);padding:var(--s-1) var(--s-2);font:400 .6875rem var(--mono)}
	.facets button{min-height:32px;padding:0 var(--s-2)}.kanban{margin-top:var(--s-2)}.kanban-note{font-size:.75rem;color:var(--text-3);background:var(--s2);padding:var(--s-2);margin-top:var(--s-3);border-radius:var(--r-xs)}.lane-group{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3);margin-top:var(--s-3)}.graph path{fill:var(--text-3)}.graph line{stroke:var(--text-3);stroke-width:.4;marker-end:url(#arrow)}.graph>small{position:absolute;left:var(--s-2);bottom:var(--s-2);font:400 .6875rem var(--mono);color:var(--text-3)}.graph button{min-height:48px;transform:translate(-50%,-50%)}.link{width:100%;min-height:40px;border:0;background:transparent;color:var(--text-2);display:grid;grid-template-columns:16px 90px 1fr;gap:var(--s-2);align-items:center;text-align:left;border-radius:var(--r-xs)}.link:hover{background:var(--s2)}.link small{grid-column:3;color:var(--text-3)}
	@media(max-width:900px){.sign>span,.bud{display:none}.sign form{width:220px}.desk{grid-template-columns:1fr}.kanban{grid-template-columns:1fr 1fr}}@media(max-width:767px){.sign{flex-wrap:wrap}.sign form{order:3;width:100%}.seg{display:none}.desk aside,.desk main .panel:not(:first-child){display:none}.two{grid-template-columns:1fr}.head,.row{grid-template-columns:1fr 56px}.head span:nth-child(2),.head span:nth-child(4),.row>code:nth-of-type(1),.row>code:nth-of-type(3){display:none}.kanban{grid-template-columns:1fr}.graph-scroll{display:none}}
	.seg{padding:var(--s-1)}.seg button,.bud{border-radius:var(--r-sm)}.panel{border-radius:var(--r-xs)}.row em{margin-top:var(--s-1)}
	.library-drawer header{display:flex;gap:var(--s-2);padding-right:var(--s-4)}.library-drawer header h2{font:400 1.0625rem var(--sign)}.library-drawer .chips span{gap:var(--s-1);padding:var(--s-1) var(--s-2)}.library-drawer article{line-height:1.6;color:var(--text-2);margin:var(--s-4) 0}.library-drawer section{border-top:1px solid var(--rule);padding:var(--s-3) 0}.library-drawer h3{font:500 .6875rem var(--mono);text-transform:uppercase;color:var(--text-3)}.library-drawer section p,.library-drawer>footer{display:flex;align-items:center;gap:var(--s-2);font:400 .6875rem var(--mono);color:var(--text-3);margin-top:var(--s-2)}
</style>
